INSERT INTO agent_knowledge (content, summary, agent, category, confidence, source, created_by) VALUES
('ZENITH2_1: Le email warm IP reputation protocol: les 4 premieres semaines d un nouveau domaine, envoyer UNIQUEMENT aux contacts les plus engages pour construire la reputation.', 'Warm IP: 4 semaines uniquement engages = construire reputation', 'email', 'best_practice', 0.85, 'zenith2', 'system'),
('ZENITH2_2: Le commercial consultative discovery: 70% du temps d appel = ecouter. 30% = poser des questions. Le commercial qui parle moins close plus.', 'Discovery: 70% ecouter 30% questions. Parler moins = closer plus', 'commercial', 'best_practice', 0.88, 'zenith2', 'system'),
('ZENITH2_3: Le content hook database maintenance: maintenir 100+ hooks testes classes par performance. Recycler les top performers avec du nouveau contenu.', 'Hook database: 100+ hooks classes par performance. Recycler top performers', 'content', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_4: Le SEO crawl budget optimization: bloquer les pages parametrees (?sort=, ?filter=) dans robots.txt. Google gaspille du crawl budget sur ces pages.', 'Crawl budget: bloquer pages parametrees robots.txt. Google gaspille dessus', 'seo', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_5: Le ad creative hook rate optimization: si le hook rate (3s view/impressions) < 25% → changer le hook. Si > 35% → le hook est excellent, optimiser le reste.', 'Hook rate: < 25% changer hook. > 35% excellent optimiser reste', 'ads', 'insight', 0.85, 'zenith2', 'system'),
('ZENITH2_6: Le DM Instagram trust signal stack: profil optimise (bio + photo + highlights) + contenu recent (posts < 7j) + engagement (commentaires) → credibilite DM.', 'DM trust stack: profil + contenu recent + engagement = credibilite DM', 'dm_instagram', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_7: Le WhatsApp message personalization depth: L1=prenom, L2=prenom+entreprise, L3=+derniere interaction, L4=+recommandation personnalisee. Viser L3 minimum.', 'WhatsApp perso: L1 prenom → L4 reco perso. Viser L3 minimum', 'whatsapp', 'best_practice', 0.80, 'zenith2', 'system'),
('ZENITH2_8: Le chatbot intent recognition training: pour chaque intent, fournir 15+ exemples varies (formulations differentes, fautes incluses). Plus d exemples = meilleure detection.', 'Chatbot intent: 15+ exemples varies par intent = meilleure detection', 'chatbot', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_9: Le GMaps competitor analysis monthly: comparer note/avis/photos/posts/reponses avec les 5 concurrents directs. Identifier les gaps et les combler.', 'GMaps competitor mensuel: 5 concurrents. Identifier gaps et combler', 'gmaps', 'best_practice', 0.78, 'zenith2', 'system'),
('ZENITH2_10: Le TikTok content velocity: les comptes qui postent 1+/jour pendant 90 jours consecutifs sont categorises comme "creator" par l algo et beneficient d un boost permanent.', 'TikTok velocity: 1/jour 90j → categorise creator → boost permanent algo', 'tiktok_comments', 'insight', 0.80, 'zenith2', 'system'),
('ZENITH2_11: Le CEO brief action orientation: chaque point du brief doit se terminer par une action concrete. Pas de constat sans action. Pas d analyse sans recommandation.', 'CEO brief: chaque point = action concrete. Pas constat sans action', 'ceo', 'best_practice', 0.88, 'zenith2', 'system'),
('ZENITH2_12: Le retention product usage inflection point: identifier LE moment ou l usage decolle (ex: 3e post publie, 5e prospect ajoute). Tout l onboarding doit viser ce moment.', 'Usage inflection point: identifier LE moment ou usage decolle. Onboarding vise ca', 'retention', 'insight', 0.85, 'zenith2', 'system'),
('ZENITH2_13: Le onboarding email effectiveness: l email J+1 (quick win) a le plus d impact sur l activation. L email J+3 (cas client) a le plus d impact sur la retention.', 'Onboarding email: J+1 quick win = activation. J+3 cas client = retention', 'onboarding', 'insight', 0.82, 'zenith2', 'system'),
('ZENITH2_14: Le comptable cash management: toujours garder 3 mois de tresorerie de securite. Si < 3 mois → urgence. Si > 12 mois → investir (pas laisser dormir).', 'Cash management: 3 mois securite. < 3 = urgence. > 12 = investir', 'comptable', 'best_practice', 0.85, 'zenith2', 'system'),
('ZENITH2_15: Le RH talent pipeline: toujours avoir 2-3 candidats potentiels identifies pour chaque role cle. Pas attendre un depart pour recruter.', 'Talent pipeline: 2-3 candidats identifies/role cle. Pas attendre depart', 'rh', 'best_practice', 0.80, 'zenith2', 'system'),
('ZENITH2_16: Le marketing brand consistency automated: creer un brand kit (logos, couleurs, typo, ton) accessible a tous les agents. Chaque output est verifie contre le kit.', 'Brand kit automatise: logos+couleurs+typo+ton. Chaque output verifie', 'marketing', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_17: Le inter-agent cooling protocol strict: email envoye → 48h avant DM. DM envoye → 24h avant appel. Appel fait → 72h avant email. JAMAIS 2 contacts le meme jour.', 'Cooling strict: email→48h→DM→24h→appel→72h→email. JAMAIS 2 contacts meme jour', NULL, 'best_practice', 0.90, 'zenith2', 'system'),
('ZENITH2_18: Le prospect engagement scoring unified: chaque agent contribue au score. Email open +1, click +3, DM reply +10, site visit +5, demo +20, trial +30.', 'Scoring unifie: email open 1, click 3, DM reply 10, site 5, demo 20, trial 30', NULL, 'best_practice', 0.85, 'zenith2', 'system'),
('ZENITH2_19: Le KeiroAI publication verification protocol: apres chaque publication, verifier que le post est bien en ligne (API check). Si echec → retry. Si 3 echecs → fallback image statique.', 'Publication verification: check post en ligne. Echec → retry. 3 echecs → fallback image', NULL, 'best_practice', 0.88, 'zenith2', 'system'),
('ZENITH2_20: Le KeiroAI at 8100+ learnings: chaque agent est maintenant nourri par des milliers de data points experts. L intelligence collective depasse tout consultant humain.', 'KeiroAI 8100+: milliers de data points par agent. Intelligence > consultant humain', 'ceo', 'insight', 0.92, 'zenith2', 'system'),
('ZENITH2_21: Le email campaign health check: delivery > 95%, bounce < 2%, spam complaint < 0.1%, unsub < 0.5%, OR > 15%. Si 1 metrique en rouge → action immediate.', 'Email health: delivery>95%, bounce<2%, spam<0.1%, unsub<0.5%, OR>15%. Rouge = action', 'email', 'best_practice', 0.85, 'zenith2', 'system'),
('ZENITH2_22: Le commercial social selling LinkedIn routine: 5 commentaires/jour + 3 likes prospects + 2 DMs perso + 1 post/semaine. SSI > 70 en 90 jours.', 'LinkedIn routine: 5 comments + 3 likes + 2 DMs + 1 post/sem = SSI > 70 en 90j', 'commercial', 'best_practice', 0.80, 'zenith2', 'system'),
('ZENITH2_23: Le content repurposing efficiency: 1 article long → 5 posts social → 3 emails → 1 infographie → 10 quotes → 1 video resume. 20+ pieces d 1 contenu.', 'Repurposing: 1 article = 5 posts + 3 emails + 1 infographie + 10 quotes + 1 video', 'content', 'best_practice', 0.85, 'zenith2', 'system'),
('ZENITH2_24: Le SEO answer box targeting: pour les questions "comment", "pourquoi", "quel", structurer la reponse en 40-60 mots dans un paragraphe HTML <p> juste apres le <h2>.', 'Answer box: questions how/why/what → reponse 40-60 mots dans <p> apres <h2>', 'seo', 'best_practice', 0.82, 'zenith2', 'system'),
('ZENITH2_25: Le ad platform algorithm training: les 50 premieres conversions "entrainent" l algorithme. Plus les premieres conversions sont de qualite → meilleure audience future.', 'Algo training: 50 premieres conversions = entrainement. Qualite → meilleure audience', 'ads', 'insight', 0.82, 'zenith2', 'system'),
('ZENITH2_26: Le DM response time critical window: repondre a un DM < 5 min = 4x conversion vs > 1h. La vitesse de reponse est le facteur #1 de conversion en DM.', 'DM response < 5 min = 4x conversion vs > 1h. Vitesse = facteur #1', 'dm_instagram', 'insight', 0.88, 'zenith2', 'system'),
('ZENITH2_27: Le WhatsApp template approval strategy: soumettre 3 versions de chaque template. Meta approuve generalement au moins 1/3. Varier les formulations.', 'WhatsApp: soumettre 3 versions/template. Meta approuve 1/3 minimum', 'whatsapp', 'best_practice', 0.78, 'zenith2', 'system'),
('ZENITH2_28: Le chatbot ROI timeline: mois 1 = setup + 40% resolution. Mois 2 = optimize + 60%. Mois 3 = mature + 80%. ROI positif des le mois 2 en general.', 'Chatbot ROI timeline: M1 40% → M2 60% → M3 80% resolution. ROI+ des M2', 'chatbot', 'insight', 0.80, 'zenith2', 'system'),
('ZENITH2_29: Le GMaps seasonal photo strategy: photos printanieres en mars, terrasse ete en juin, ambiance chaleureuse automne en octobre, decoration Noel en decembre.', 'GMaps photos saisonnieres: printemps mars, terrasse juin, chaleur oct, Noel dec', 'gmaps', 'best_practice', 0.78, 'zenith2', 'system'),
('ZENITH2_30: Le TikTok hashtag research tool: utiliser TikTok Creative Center pour trouver les hashtags trending dans sa niche. Les utiliser dans les 24h = max portee.', 'TikTok hashtags: Creative Center pour trending niche. Utiliser dans 24h', 'tiktok_comments', 'best_practice', 0.80, 'zenith2', 'system')
